package com.company.supervision.api;import com.company.supervision.application.scheduling.AdvancedScheduleService;import com.company.supervision.entity.dto.ApiResult;import com.company.supervision.entity.dto.schedule.ScheduleRule;import org.springframework.web.bind.annotation.*;@RestController @RequestMapping("/schedules")public class ScheduleController{private final AdvancedScheduleService s;public ScheduleController(AdvancedScheduleService s){this.s=s;}@PostMapping("/preview")public ApiResult<?>preview(@RequestBody ScheduleRule r){return ApiResult.ok(s.preview(r));}}